    [AcceptVerbs(HttpVerbs.Get | HttpVerbs.Post)]
    public PartialViewResult GetUsers(string id)
    {
      var model = new tbl_AspNetUserRoles_FULL_partial();

      model.id = id;

      SqlParameter[] parameters = new SqlParameter[]{
                    new SqlParameter("@Id",SqlDbType.NVarChar){Value = (id ?? "").ToString()},
                };

      model.Items = db.Database.SqlQuery<Firstronic.Framework.Account.tbl_AspNetUserRoles_FULL>($@"SELECT AspNetUserRoles.UserId, AspNetUsers.Name, AspNetUsers.Badge, AspNetUsers.UserName FROM AspNetUserRoles INNER JOIN AspNetUsers ON AspNetUserRoles.UserId = AspNetUsers.Id WHERE AspNetUserRoles.RoleId=@Id", parameters).ToArray().ToList().AsQueryable();

      return PartialView("_Users", model);
    }

    [AcceptVerbs(HttpVerbs.Get | HttpVerbs.Post)]
    public bool DeleteUsers(string UserId,string RoleId)
    {
      SqlParameter[] parameters = new SqlParameter[]{
                    new SqlParameter("@UserId",SqlDbType.NVarChar){Value = UserId},
                    new SqlParameter("@RoleId",SqlDbType.NVarChar){Value = RoleId},
                };

      var result = db.ExecuteCommand($@"DELETE FROM AspNetUserRoles WHERE UserId=@UserId AND RoleId=@RoleId", parameters);

      return true;
    }

    [AcceptVerbs(HttpVerbs.Get | HttpVerbs.Post)]
    public bool AddUsers(string vUserId, string vRoleId)
    {
      SqlParameter[] userRolParameters = new SqlParameter[]{
              new SqlParameter("@UserId",SqlDbType.NVarChar){Value = vUserId},
              new SqlParameter("@RoleId",SqlDbType.NVarChar){Value = vRoleId}
          };

      DataTable dtExist = Firstronic.Framework.Queries.GetDatatableFromQuery("SELECT [UserId],[RoleId] FROM [AspNetUserRoles] WHere UserId=@UserId AND RoleId=@RoleId", userRolParameters);

      if (dtExist.Rows.Count == 0)
      {
        var result = db.ExecuteCommand($@"INSERT INTO [dbo].[AspNetUserRoles] (UserId, RoleId) VALUES (@UserId, @RoleId)", userRolParameters);
      }

      return true;
    }
  }
}

