using System;
using System.Collections.Generic;
using System.Linq;
using System.Web;
using System.Web.Mvc;

namespace Firstronic.Areas.Personnel.Controllers
{
  public class ReportsController : BaseSecurityController
  {

    //===============================================================
    // Bonus Report
    //===============================================================
    [Authorize(Roles = "BF Administrator,BF Efficiency Report")]
    public ActionResult BonusHistory()
    {
      return View();
    }

    [AcceptVerbs(HttpVerbs.Get | HttpVerbs.Post)]
    public PartialViewResult GetBonusDataTable(DateTime stardate, DateTime enddate, int v_Type, string Gafete = "")
    {

      // v_Type: 1 BackFlahs, 2 Delta, 3 Summary

      var model = new Firstronic.Areas.Personnel.Models.Bonus_History();

      model.stardate = stardate;

      model.enddate = enddate.AddDays(+1);

      model.Gafete = Gafete;

      return PartialView("BonusHistory_Details", model);

    }

  }
}

